```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {

  // Connect to the database
  auto conn = sqlgen::sqlite::connect(db_path).value();

  // Insert each record
  for (const auto& record : records) {
    sqlgen::insert_into(conn, record).value();
  }
}

void modify_eas_records_by_id(const std::string& table_name,
                              int record_id,
                              const std::string& col_name,
                              const auto& new_value) {
  // Connect to the database
  auto conn = sqlgen::sqlite::connect(db_path).value();

  // Determine which table to update based on table_name
  if (table_name == "Student") {
    // For Student table, the primary key is SNo (Varchar<10>)
    // We need to convert record_id to string since SNo is Varchar<10>
    std::string sno_str = std::to_string(record_id);

    // Update based on column name
    if (col_name == "SName") {
      sqlgen::update(conn, Student{.SNo = sno_str, .SName = std::string(new_value)})
          .where("SNo"_col == sno_str)
          .value();
    } else if (col_name == "Sex") {
      sqlgen::update(conn, Student{.SNo = sno_str, .Sex = new_value})
          .where("SNo"_col == sno_str)
          .value();
    } else if (col_name == "Birthday") {
      sqlgen::update(conn, Student{.SNo = sno_str, .Birthday = new_value})
          .where("SNo"_col == sno_str)
          .value();
    } else if (col_name == "Major") {
      sqlgen::update(conn, Student{.SNo = sno_str, .Major = new_value})
          .where("SNo"_col == sno_str)
          .value();
    } else if (col_name == "Scores") {
      sqlgen::update(conn, Student{.SNo = sno_str, .Scorses = new_value})
          .where("SNo"_col == sno_str)
          .value();
    } else if (col_name == "Remark") {
      sqlgen::update(conn, Student{.SNo = sno_str, .Remark = std::string(new_value)})
          .where("SNo"_col == sno_str)
          .value();
    }

  } else if (table_name == "Course") {
    // Update Course table by CID
    if (col_name == "CName") {
      sqlgen::update(conn, Course{.CID = record_id, .CName = std::string(new_value)})
          .where("CID"_col == record_id)
          .value();
    } else if (col_name == "Term") {
      sqlgen::update(conn, Course{.CID = record_id, .Term = new_value})
          .where("CID"_col == record_id)
          .value();
    } else if (col_name == "CTime") {
      sqlgen::update(conn, Course{.CID = record_id, .CTime = new_value})
          .where("CID"_col == record_id)
          .value();
    } else if (col_name == "Credit") {
      sqlgen::update(conn, Course{.CID = record_id, .Credit = new_value})
          .where("CID"_col == record_id)
          .value();
    }

  } else if (table_name == "Score") {
    // Update Score table by ScID
    if (col_name == "SNo") {
      sqlgen::update(conn, Score{.ScID = record_id, .SNo = std::string(new_value)})
          .where("ScID"_col == record_id)
          .value();
    } else if (col_name == "CID") {
      sqlgen::update(conn, Score{.ScID = record_id, .CID = new_value})
          .where("ScID"_col == record_id)
          .value();
    } else if (col_name == "Score") {
      sqlgen::update(conn, Score{.ScID = record_id, .Score = new_value})
          .where("ScID"_col == record_id)
          .value();
    }

  } else if (table_name == "Major") {
    // Update Major table by MID
    if (col_name == "MName") {
      sqlgen::update(conn, Major{.MID = record_id, .MName = std::string(new_value)})
          .where("MID"_col == record_id)
          .value();
    }
  }
}

void delete_eas_records_by_id(const std::string& table_name,
                              const std::string& record_id) {
  // Connect to the database
  auto conn = sqlgen::sqlite::connect(db_path).value();

  // Delete based on table name and primary key
  if (table_name == "Student") {
    // For Student table, primary key is SNo (Varchar<10>)
    sqlgen::remove_from<Student>(conn)
        .where("SNo"_col == record_id)
        .value();

  } else if (table_name == "Course") {
    // For Course table, primary key is CID (uint32_t)
    int cid = std::stoi(record_id);
    sqlgen::remove_from<Course>(conn)
        .where("CID"_col == cid)
        .value();

  } else if (table_name == "Score") {
    // For Score table, primary key is ScID (uint32_t)
    int scid = std::stoi(record_id);
    sqlgen::remove_from<Score>(conn)
        .where("ScID"_col == scid)
        .value();

  } else if (table_name == "Major") {
    // For Major table, primary key is MID (uint32_t)
    int mid = std::stoi(record_id);
    sqlgen::remove_from<Major>(conn)
        .where("MID"_col == mid)
        .value();
  }
}
```

Key points about this implementation:

1. **add_eas_records**: Uses `sqlgen::insert_into` to insert each record in the vector into the specified table.

2. **modify_eas_records_by_id**: 
   - Handles each table type separately since they have different primary keys and column structures
   - Uses `sqlgen::update` with a WHERE clause to modify the specific record
   - Converts the record_id appropriately for each table type

3. **delete_eas_records_by_id**:
   - Uses `sqlgen::remove_from` with a WHERE clause to delete the specific record
   - Converts the string record_id to the appropriate type for each table
   - Handles the Student table specially since its primary key is a Varchar rather than an integer

The implementation follows the sqlgen library's patterns and properly handles the different data types and primary key structures for each table.

