bool soft_delete_records(const std::vector<int>& ids) {
    if (ids.empty()) {
        return true; // Nothing to delete
    }

    try {
        // Connect to the SQLite database
        auto db = sqlgen::database<sqlgen::sqlite>("test_db.sqlite");

        // Start a transaction for better performance with multiple updates
        auto transaction = db.transaction();

        // Create the update query using sqlgen
        auto update_query = sqlgen::update<Document>()
            .set(&Document::is_deleted, 1)
            .set(&Document::deleted_at, sqlgen::DateTime::now())
            .where(sqlgen::in(&Document::doc_id, ids));

        // Execute the update
        db.execute(update_query);

        // Commit the transaction
        transaction.commit();

        return true;
    } catch (const std::exception& e) {
        // Handle any database errors
        // In a real application, you might want to log the error
        return false;
    }
}

}  // namespace soft_delete_records
