  // Unix epoch for 2023-01-01 20:00:00 UTC
  EXPECT_GT(party.start_epoch, 0);

  // Duration: 20:00 to 02:00 next day is < 1 day, so 0 days
  EXPECT_EQ(party.duration_days, 0);

  // Verify Conference
