#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <iostream>

namespace upsert_inventory_items {

struct Inventory {
  sqlgen::PrimaryKey<int> item_id;
  std::string name;
  int quantity;
};

/**
 * description: upsert_inventory_items.
 * This function demonstrates how to use upsert (insert or replace) statements in sqlgen write API.
 * It inserts or replaces the given inventory items in the Inventory table.
 */
bool upsert_inventory_items(const std::vector<Inventory>& items) {
  try {
    // Create database connection
    sqlgen::SQLiteDB db("test_db.sqlite");

    // Create table if it doesn't exist
    db.create_table<Inventory>();

    // Perform upsert operations using replace (SQLite's INSERT OR REPLACE)
    auto tx = db.transaction();
    for (const auto& item : items) {
      tx.replace(item);
    }
    tx.commit();

    // Verify upsert behavior by reading back all items
    auto read_items = db.read<Inventory>();

    // Check if all inserted items exist and have correct values
    for (const auto& original_item : items) {
      bool found = false;
      for (const auto& read_item : read_items) {
        if (read_item.item_id == original_item.item_id) {
          found = true;
          // Verify the data matches
          if (read_item.name != original_item.name || read_item.quantity != original_item.quantity) {
            std::cerr << "Verification failed for item_id: " << original_item.item_id 
                      << ". Data mismatch after upsert." << std::endl;
            return false;
          }
          break;
        }
      }

      if (!found) {
        std::cerr << "Verification failed for item_id: " << original_item.item_id 
                  << ". Item not found after upsert." << std::endl;
        return false;
      }
    }

    std::cout << "Upsert operation completed successfully. " 
              << items.size() << " items processed." << std::endl;
    return true;

  } catch (const std::exception& e) {
    std::cerr << "Error in upsert_inventory_items: " << e.what() << std::endl;
    return false;
  }
}

}  // namespace upsert_inventory_items

