  double unit_price;
  int quantity;
  std::optional<double> discount_rate;
  std::optional<double> tax_rate;
};

struct OrderMetrics {
  int item_id;
  int order_id;
  int product_id;
  double unit_price;
  int quantity;
  double discount_rate;
  double tax_rate;
  double gross_total;
  double discounted_total;
  double final_total;
  double unit_cost;
  int quantity_group;
  double estimated_profit;
};

/**
 * Calculate per-item order metrics by loading the provided items into a temporary SQLite table
 * and evaluating SQL expressions for totals, discounts, taxes, cost, grouping, and estimated profit.
 * @param items Vector of OrderItem records to analyze.
 * @return std::vector<OrderMetrics> Analysis results for each order item.
 */
std::vector<OrderMetrics> calculate_order_metrics_impl(const std::vector<OrderItem>& items) {
  // Create an in-memory SQLite database
  auto db = std::make_shared<sqlgen::SQLiteDB>(":memory:");

  // Create the OrderItem table
  db->execute(R"(
    CREATE TABLE OrderItem (
      item_id INTEGER PRIMARY KEY,
      order_id INTEGER NOT NULL,
      product_id INTEGER NOT NULL,
      unit_price REAL NOT NULL,
      quantity INTEGER NOT NULL,
      discount_rate REAL,
      tax_rate REAL
    )
  )");

  // Insert all items into the table
  auto insert_stmt = db->prepare(R"(
    INSERT INTO OrderItem (item_id, order_id, product_id, unit_price, quantity, discount_rate, tax_rate)
    VALUES (?, ?, ?, ?, ?, ?, ?)
  )");

  for (const auto& item : items) {
    insert_stmt->bind(1, item.item_id.value());
    insert_stmt->bind(2, item.order_id);
    insert_stmt->bind(3, item.product_id);
    insert_stmt->bind(4, item.unit_price);
    insert_stmt->bind(5, item.quantity);

    if (item.discount_rate.has_value()) {
      insert_stmt->bind(6, item.discount_rate.value());
    } else {
      insert_stmt->bind(6, nullptr);
    }

    if (item.tax_rate.has_value()) {
      insert_stmt->bind(7, item.tax_rate.value());
    } else {
      insert_stmt->bind(7, nullptr);
    }

    insert_stmt->execute();
    insert_stmt->reset();
  }

  // Execute the comprehensive metrics query
  auto select_stmt = db->prepare(R"(
    SELECT 
      item_id,
      order_id,
      product_id,
      unit_price,
      quantity,
      COALESCE(discount_rate, 0) as discount_rate,
      COALESCE(tax_rate, 0) as tax_rate,
      (unit_price * quantity) as gross_total,
      (unit_price * quantity * (1 - COALESCE(discount_rate, 0)/100)) as discounted_total,
      (unit_price * quantity * (1 - COALESCE(discount_rate, 0)/100) * (1 + COALESCE(tax_rate, 0)/100)) as final_total,
      (unit_price * quantity / quantity) as unit_cost,
      (quantity % 10) as quantity_group,
      (unit_price * 0.3) as estimated_profit
    FROM OrderItem
    ORDER BY item_id
  )");

  std::vector<OrderMetrics> results;

  while (select_stmt->step()) {
    OrderMetrics metrics;

    metrics.item_id = select_stmt->get<int>(0);
    metrics.order_id = select_stmt->get<int>(1);
    metrics.product_id = select_stmt->get<int>(2);
    metrics.unit_price = select_stmt->get<double>(3);
    metrics.quantity = select_stmt->get<int>(4);
    metrics.discount_rate = select_stmt->get<double>(5);
    metrics.tax_rate = select_stmt->get<double>(6);
    metrics.gross_total = select_stmt->get<double>(7);
    metrics.discounted_total = select_stmt->get<double>(8);
    metrics.final_total = select_stmt->get<double>(9);
    metrics.unit_cost = select_stmt->get<double>(10);
    metrics.quantity_group = select_stmt->get<int>(11);
    metrics.estimated_profit = select_stmt->get<double>(12);

    results.push_back(metrics);
  }

  return results;
}

}  // namespace calculate_order_metrics
```

This implementation:

1. **Creates an in-memory SQLite database** instead of connecting to "test_db.sqlite" since the function takes input via the `items` parameter rather than reading from a file database.

2. **Handles optional fields** properly by using `COALESCE` to convert NULL values to 0 for calculations.

3. **Performs all required arithmetic operations**:
   - Multiplication: `unit_price * quantity` for gross total
   - Division: `discount_rate/100`, `tax_rate/100`, and `total / quantity` for unit cost
   - Modulo: `quantity % 10` for quantity grouping
   - Addition/subtraction in the discount and tax calculations

4. **Calculates comprehensive business metrics** including:
   - Gross total (before discounts/taxes)
   - Discounted total (after discount)
   - Final total (after discount and tax)
   - Unit cost per item
   - Quantity groups using modulo 10
   - Estimated profit (30% of unit price)

5. **Returns the complete analysis** as a vector of `OrderMetrics` structures containing all calculated values for each order item.

The function properly handles the case where discount_rate or tax_rate might be null by using `COALESCE` to substitute 0, ensuring all calculations work correctly.

