  sqlgen::PrimaryKey<int> child_id;
  sqlgen::ForeignKey<int, Parent, "parent_id"> parent_id;
  std::string note;
};

/**
 * Demonstrates cascade delete behavior in SQLite using foreign key constraints.
 * Returns: bool.
 */
bool cascade_delete_demo() {
  try {
    // Create database connection
    sqlgen::Database<sqlgen::SQLite> db("test_db.sqlite");

    // Enable foreign key constraints (required for SQLite)
    db.execute("PRAGMA foreign_keys = ON");

    // Create tables
    db.create_table<Parent>();
    db.create_table<Child>();

    // Insert parent record
    Parent parent{1, "Test Parent"};
    db.insert(parent);

    // Insert child records with same parent_id
    Child child1{1, 1, "Child 1"};
    Child child2{2, 1, "Child 2"};
    Child child3{3, 1, "Child 3"};

    db.insert(child1);
    db.insert(child2);
    db.insert(child3);

    // Verify initial child count
    auto initial_children = db.select<Child>();
    if (initial_children.size() != 3) {
      std::cout << "Initial child count incorrect: " << initial_children.size() << std::endl;
      return false;
    }

    // Delete parent (this should cascade to children)
    db.remove<Parent>(1);

    // Check if child records were automatically deleted
    auto remaining_children = db.select<Child>();

    // Verify result
    bool cascade_worked = remaining_children.empty();

    if (cascade_worked) {
      std::cout << "Cascade delete successful: All child records were automatically deleted" << std::endl;
    } else {
      std::cout << "Cascade delete failed: " << remaining_children.size() << " child records remain" << std::endl;
    }

    // Clean up: drop tables
    db.drop_table<Child>();
    db.drop_table<Parent>();

    return cascade_worked;

  } catch (const std::exception& e) {
    std::cerr << "Error in cascade_delete_demo: " << e.what() << std::endl;
    return false;
  }
}

