namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a supplier and the name of a product, if any.
 */
std::vector<SupProd> full_join_suppliers_products() {
  using namespace sqlgen::sqlite;

  // Open database connection
  auto db = open("test_db.sqlite");

  // Since SQLite doesn't natively support FULL JOIN, we simulate it using LEFT JOIN and UNION
  // First part: Suppliers with their products (LEFT JOIN)
  auto left_join_query = sqlgen::select(
    sqlgen::columns(&Supplier::name, &Product::name),
    sqlgen::from<Supplier>(),
    sqlgen::left_join<Product>(sqlgen::on(&Supplier::supplier_id == &Product::supplier_id))
  );

  // Second part: Products without suppliers (RIGHT JOIN simulation)
  // Since SQLite doesn't have RIGHT JOIN, we reverse the tables and use LEFT JOIN
  auto right_join_query = sqlgen::select(
    sqlgen::columns(&Supplier::name, &Product::name),
    sqlgen::from<Product>(),
    sqlgen::left_join<Supplier>(sqlgen::on(&Product::supplier_id == &Supplier::supplier_id)),
    sqlgen::where(sqlgen::is_null(&Supplier::supplier_id))
  );

  // Execute both queries and combine results
  auto left_results = left_join_query.execute(db);
  auto right_results = right_join_query.execute(db);

  // Combine results into final vector
  std::vector<SupProd> results;

  // Process left join results (suppliers with or without products)
  for (const auto& row : left_results) {
    SupProd item;
    item.supplier_name = std::get<0>(row);
    if (std::get<1>(row).has_value()) {
      item.product_name = std::get<1>(row).value();
    }
    results.push_back(item);
  }

  // Process right join results (products without suppliers)
  for (const auto& row : right_results) {
    SupProd item;
    // Supplier name will be null for these rows
    item.supplier_name = ""; // Empty string for products without suppliers
    if (std::get<1>(row).has_value()) {
      item.product_name = std::get<1>(row).value();
    }
    results.push_back(item);
  }

  return results;
}

}  // namespace full_join_suppliers_products
