};

struct Employee {
  sqlgen::PrimaryKey<int> employee_id;
  int department_id;
  std::string first_name;
  std::string last_name;
  double salary;
};

struct JoinResult {
  std::optional<std::string> department_name;
  std::optional<std::string> first_name;
  std::optional<std::string> last_name;
  std::optional<double> salary;
};

struct JoinAnalysis {
  std::vector<JoinResult> inner_join_results;
  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

/**
 * analyze_department_employees
 * Provides data-join analysis between Department and Employee input collections by
 * creating temporary SQL tables, inserting the provided rows, and executing a
 * variety of join queries to produce join-output samples.
 * Returns: JoinAnalysis.
 */
JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  JoinAnalysis analysis;

  // Create SQLite database connection
  sqlgen::SQLite db("test_db.sqlite");

  // Create tables
  db.execute(R"(
    DROP TABLE IF EXISTS Department;
  )");

  db.execute(R"(
    CREATE TABLE Department (
      department_id INTEGER PRIMARY KEY,
      department_name TEXT NOT NULL,
      location TEXT
    );
  )");

  db.execute(R"(
    DROP TABLE IF EXISTS Employee;
  )");

  db.execute(R"(
    CREATE TABLE Employee (
      employee_id INTEGER PRIMARY KEY,
      department_id INTEGER,
      first_name TEXT NOT NULL,
      last_name TEXT NOT NULL,
      salary REAL NOT NULL,
      FOREIGN KEY (department_id) REFERENCES Department(department_id)
    );
  )");

  // Insert department data
  for (const auto& dept : depts) {
    db.execute(R"(
      INSERT INTO Department (department_id, department_name, location)
      VALUES (?, ?, ?)
    )", dept.department_id, dept.department_name, dept.location);
  }

  // Insert employee data
  for (const auto& emp : emps) {
    db.execute(R"(
      INSERT INTO Employee (employee_id, department_id, first_name, last_name, salary)
      VALUES (?, ?, ?, ?, ?)
    )", emp.employee_id, emp.department_id, emp.first_name, emp.last_name, emp.salary);
  }

  // 1. INNER JOIN - Employees with assigned departments
  auto inner_join_stmt = db.prepare(R"(
    SELECT d.department_name, e.first_name, e.last_name, e.salary
    FROM Department d
    INNER JOIN Employee e ON d.department_id = e.department_id
  )");

  while (inner_join_stmt.step()) {
    JoinResult result;
    result.department_name = inner_join_stmt.get<std::string>(0);
    result.first_name = inner_join_stmt.get<std::string>(1);
    result.last_name = inner_join_stmt.get<std::string>(2);
    result.salary = inner_join_stmt.get<double>(3);
    analysis.inner_join_results.push_back(result);
  }

  // 2. LEFT JOIN - All employees (even without departments)
  auto left_join_stmt = db.prepare(R"(
    SELECT d.department_name, e.first_name, e.last_name, e.salary
    FROM Employee e
    LEFT JOIN Department d ON e.department_id = d.department_id
  )");

  while (left_join_stmt.step()) {
    JoinResult result;
    result.department_name = left_join_stmt.get<std::optional<std::string>>(0);
    result.first_name = left_join_stmt.get<std::string>(1);
    result.last_name = left_join_stmt.get<std::string>(2);
    result.salary = left_join_stmt.get<double>(3);
    analysis.left_join_results.push_back(result);
  }

  // 3. RIGHT JOIN - All departments (even without employees)
  // SQLite doesn't support RIGHT JOIN directly, so we emulate it with LEFT JOIN
  auto right_join_stmt = db.prepare(R"(
    SELECT d.department_name, e.first_name, e.last_name, e.salary
    FROM Department d
    LEFT JOIN Employee e ON d.department_id = e.department_id
  )");

  while (right_join_stmt.step()) {
    JoinResult result;
    result.department_name = right_join_stmt.get<std::string>(0);
    result.first_name = right_join_stmt.get<std::optional<std::string>>(1);
    result.last_name = right_join_stmt.get<std::optional<std::string>>(2);
    result.salary = right_join_stmt.get<std::optional<double>>(3);
    analysis.right_join_results.push_back(result);
  }

  // 4. FULL JOIN - All employees and departments
  // SQLite doesn't support FULL JOIN directly, so we emulate it with UNION of LEFT and RIGHT joins
  auto full_join_stmt = db.prepare(R"(
    SELECT d.department_name, e.first_name, e.last_name, e.salary
    FROM Employee e
    LEFT JOIN Department d ON e.department_id = d.department_id
    UNION
    SELECT d.department_name, e.first_name, e.last_name, e.salary
    FROM Department d
    LEFT JOIN Employee e ON d.department_id = e.department_id
  )");

  while (full_join_stmt.step()) {
    JoinResult result;
    result.department_name = full_join_stmt.get<std::optional<std::string>>(0);
    result.first_name = full_join_stmt.get<std::optional<std::string>>(1);
    result.last_name = full_join_stmt.get<std::optional<std::string>>(2);
    result.salary = full_join_stmt.get<std::optional<double>>(3);
    analysis.full_join_results.push_back(result);
  }

  return analysis;
}

}  // namespace analyze_department_employees

