std::vector<WeekdayStats> weekday_sales_analysis() {
  // Connect to the SQLite database
  sqlgen::SQLiteDB db("test_db.sqlite");

  // Create the query to extract weekday and aggregate quantities
  auto query = sqlgen::query<Sales>()
    .select(
      sqlgen::expr("strftime('%w', sale_time)").as("weekday"),
      sqlgen::sum(Sales::quantity).as("total_quantity")
    )
    .group_by(sqlgen::expr("strftime('%w', sale_time)"))
    .order_by(sqlgen::expr("weekday"));

  // Execute the query and get results
  auto results = db.execute(query);

  // Convert results to WeekdayStats vector
  std::vector<WeekdayStats> stats;
  for (const auto& row : results) {
    WeekdayStats stat;
    stat.weekday = std::stoi(row["weekday"].template get<std::string>());
    stat.total_quantity = row["total_quantity"].template get<int>();
    stats.push_back(stat);
  }

  return stats;
}

}  // namespace weekday_sales_analysis
