Here's the complete implementation of the function using the `sqlgen` library:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

namespace create_table_as_select {

struct Source {
  sqlgen::PrimaryKey<int> id;
  int value;
};

struct Target {
  int value;
};

/**
 * This function demonstrates creating a table from a select query.
 * Returns: query value.
 */
inline auto create_table_as_select() {
    // Create a SELECT query that filters records where value > 100
    auto select_query = sqlgen::select(sqlgen::columns(&Target::value))
                        .from<Source>()
                        .where(sqlgen::gt(&Source::value, 100));

    // Create the CREATE TABLE AS SELECT statement
    auto query = sqlgen::create_table<Target>().as_select(select_query);

    return query;
}

}  // namespace create_table_as_select
```

Alternative implementation using a more concise approach:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

namespace create_table_as_select {

struct Source {
  sqlgen::PrimaryKey<int> id;
  int value;
};

struct Target {
  int value;
};

/**
 * This function demonstrates creating a table from a select query.
 * Returns: query value.
 */
inline auto create_table_as_select() {
    // Construct the CREATE TABLE AS SELECT statement in one expression
    return sqlgen::create_table<Target>().as_select(
        sqlgen::select(sqlgen::columns(&Target::value))
            .from<Source>()
            .where(sqlgen::gt(&Source::value, 100))
    );
}

}  // namespace create_table_as_select
```

Both implementations will generate SQL similar to:
```sql
CREATE TABLE Target AS SELECT value FROM Source WHERE value > 100
```

The key points of this implementation:

1. **`sqlgen::create_table<Target>()`** - Creates a CREATE TABLE statement for the Target struct
2. **`.as_select()`** - Specifies that the table should be populated from a SELECT query
3. **`sqlgen::select(sqlgen::columns(&Target::value))`** - Selects only the `value` column to match the Target structure
4. **`.from<Source>()`** - Specifies the source table
5. **`.where(sqlgen::gt(&Source::value, 100))`** - Adds the filter condition `value > 100`

The second implementation is more concise and follows the fluent interface pattern commonly used in SQL generation libraries.

